import{_ as t,o as r,c as a,ag as n}from"./chunks/framework.ePeAWSvT.js";const g=JSON.parse('{"title":"Key Scraping","description":"","frontmatter":{},"headers":[],"relativePath":"guide/datahub-key-scraping.md","filePath":"guide/datahub-key-scraping.md"}'),o={name:"guide/datahub-key-scraping.md"};function i(s,e,d,l,h,c){return r(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="key-scraping" tabindex="-1">Key Scraping <a class="header-anchor" href="#key-scraping" aria-label="Permalink to &quot;Key Scraping&quot;">​</a></h1><p>When a record is created inside of a system, the Central engine can retrieve the new key generated for that record. Central will then save that key inside its database to be used for any subsequent call to update that record. This is referred to as <strong>indexing the record</strong>. Keys that have been scraped and stored inside of an index can also be used as a cross-reference on Foreign Key Maps. See <a href="./monitor-maintain-index.html">Maintain Index</a> for information on managing indexed records.</p><p>Endpoints with key replication configured display a <i class="fa-solid fa-key text-warning"></i> icon on their endpoint card in the Data Hub.</p><h2 id="key-scraping-action" tabindex="-1">Key Scraping Action <a class="header-anchor" href="#key-scraping-action" aria-label="Permalink to &quot;Key Scraping Action&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Input</th><th>Description</th></tr></thead><tbody><tr><td><strong>Key Scraping</strong></td><td><strong>Title:</strong> A freeform label you give to the Action.</td></tr><tr><td></td><td><strong>Key Name:</strong> The name that the key is given inside of the index. The default value is ID; however, you are able to give the Key a more specific name.</td></tr><tr><td></td><td><strong>Key Source:</strong> Connectors (directing it to look in the save response for the key) and Response Headers (directing it to look in the response headers for the key).</td></tr><tr><td></td><td><strong>Connector Property:</strong> If the source is a Connector, it will be a path to the property of the key, e.g. &quot;ID.&quot; If the source is Response Headers, it will be a path to the specific header that holds the key, e.g. <code>..Location[0]</code></td></tr><tr><td></td><td><strong>Transforms:</strong> Allows you to transform the response data the key in Central is returned to Central.</td></tr><tr><td></td><td><strong>Other Key Sources:</strong> Allows you to instruct Central where to find the key in a response if there is an atypical response body after a save.</td></tr></tbody></table><h2 id="edit-or-delete-the-primary-key-action" tabindex="-1">Edit or Delete the Primary Key Action <a class="header-anchor" href="#edit-or-delete-the-primary-key-action" aria-label="Permalink to &quot;Edit or Delete the Primary Key Action&quot;">​</a></h2><ol><li><p>Select <strong>Build</strong> &gt; <strong>Data Hubs</strong> from the main menu.</p></li><li><p>Select the appropriate <strong>Data Hub</strong>; then, select an <strong>Endpoint</strong> to edit.</p></li><li><p>Ensure the <strong>Data Source</strong> tab is selected.</p></li><li><p>Select the <strong>On Save</strong> tab from the Events column.</p></li><li><p>Then, use the below table to determine next steps:</p></li></ol><h3 id="edit-the-primary-key-action" tabindex="-1">Edit the Primary Key Action <a class="header-anchor" href="#edit-the-primary-key-action" aria-label="Permalink to &quot;Edit the Primary Key Action&quot;">​</a></h3><ol><li><p>Select <strong>menu</strong> &gt; <strong>Edit</strong> in the ObtainPrimaryKey card.</p></li><li><p>Enter a <strong>Title</strong>.</p></li><li><p>Select a <strong>Source</strong>.</p></li><li><p>As needed, toggle <strong>Requires Load</strong>.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The Requires Load toggle allows Central to query the system to find the record&#39;s key that was created if it is not in the response.</p></div></li><li><p>Enter a <strong>Connector Property</strong>.</p></li><li><p>As needed, select the <strong>arrow</strong> to add <strong>Transforms</strong>.</p></li></ol><h3 id="delete-the-primary-key-action" tabindex="-1">Delete the Primary Key Action <a class="header-anchor" href="#delete-the-primary-key-action" aria-label="Permalink to &quot;Delete the Primary Key Action&quot;">​</a></h3><ol><li>Select <strong>menu</strong> &gt; <strong>Delete</strong> in the ObtainPrimaryKey card.</li><li>Select <strong>OK</strong> to confirm.</li></ol><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./datahub-endpoint-config.html">Endpoint Configuration</a> — Configure endpoint actions and parameterization</li><li><a href="./datahub-action-mapping.html">Action Mapping</a> — Map endpoint actions to Common Model properties</li><li><a href="./monitor-maintain-index.html">Maintain Index</a> — Manage the entity index where scraped keys are stored</li><li><a href="./datahub-endpoint-settings.html">Endpoint Settings</a> — Configure Override Key Source and other key-related settings</li></ul>',13)])])}const y=t(o,[["render",i]]);export{g as __pageData,y as default};
